Passing tests: 5 (all tests, no more todos)
Recent changes: Green phase added reproduction logic — a Map tracks dead neighbor counts during the survival loop, then collects dead cells with exactly 3 live neighbors as births. Result is [...survivors, ...births].

Current implementation:
```typescript
export function nextGeneration(
  liveCells: [number, number][],
): [number, number][] {
  const liveSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));

  const survivors: [number, number][] = [];
  const deadNeighborCounts = new Map<string, number>();

  for (const [x, y] of liveCells) {
    let neighborCount = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        if (liveSet.has(key)) {
          neighborCount++;
        } else {
          deadNeighborCounts.set(key, (deadNeighborCounts.get(key) ?? 0) + 1);
        }
      }
    }
    if (neighborCount === 2 || neighborCount === 3) {
      survivors.push([x, y]);
    }
  }

  const births: [number, number][] = [];
  for (const [key, count] of deadNeighborCounts) {
    if (count === 3) {
      const [x, y] = key.split(",").map(Number);
      births.push([x, y] as [number, number]);
    }
  }

  return [...survivors, ...births];
}
```

